class Solution {
public:
    vector<int> insertionSort(vector<int>& nums) {
        int n = nums.size();
        for (int i = 1; i < n; i++) {
            int key = nums[i];
            int j = i - 1;
            while (j >= 0 && nums[j] > key) {
                nums[j + 1] = nums[j];
                j--;
            }
            nums[j + 1] = key;
        }
        return nums;
    }
};

class Solution {
  public:
    vector<int> shortestPath(vector<vector<int>>& edges, int N,int M){
        vector<vector<int>> adj(N);
        for(auto &e : edges){
            adj[e[0]].push_back(e[1]);
            adj[e[1]].push_back(e[0]);
        }
        vector<int> dist(N, -1);
        queue<int> q;
        int src = 0;
        dist[src] = 0;
        q.push(src);
        while(!q.empty()){
            int node = q.front(); q.pop();
            for(int v : adj[node]){
                if(dist[v] == -1){
                    dist[v] = dist[node] + 1;
                    q.push(v);
                }
            }
        }
        return dist;
    }
};

class Solution {
public:
    int sumSubarrayMins(vector<int> &arr) {
        const int MOD = 1e9 + 7;
        int n = arr.size();
        // For each element arr[i] taken as the minimum of a subarray:
        //   left  = number of choices for the subarray's start  (i - previous strictly-smaller index)
        //   right = number of choices for the subarray's end    (next smaller-or-equal index - i)
        // Using strict-less on the left and less-or-equal on the right avoids double-counting equal values.
        vector<int> ple(n); // index of previous strictly-smaller element (-1 if none)
        vector<int> nle(n); // index of next smaller-or-equal element (n if none)
        stack<int> st;
        for (int i = 0; i < n; i++) {
            while (!st.empty() && arr[st.top()] >= arr[i]) st.pop();
            ple[i] = st.empty() ? -1 : st.top();
            st.push(i);
        }
        while (!st.empty()) st.pop();
        for (int i = n - 1; i >= 0; i--) {
            while (!st.empty() && arr[st.top()] > arr[i]) st.pop();
            nle[i] = st.empty() ? n : st.top();
            st.push(i);
        }
        long long ans = 0;
        for (int i = 0; i < n; i++) {
            long long left = i - ple[i];
            long long right = nle[i] - i;
            ans = (ans + (left * right % MOD) * arr[i]) % MOD;
        }
        return (int)ans;
    }
};

class Solution{
public:
    int stockBuySell(vector<int> arr, int n){
        if(n <= 1) return 0;
        int minPrice = arr[0];
        int maxProfit = 0;
        for(int i = 1; i < n; i++){
            maxProfit = max(maxProfit, arr[i] - minPrice);
            minPrice = min(minPrice, arr[i]);
        }
        return maxProfit;
    }
};

class Solution {
public:
  vector<int> maxSumCombinations(vector<int> &nums1, vector<int> &nums2, int k) {
    int n = nums1.size();
    vector<int> a = nums1, b = nums2;
    sort(a.begin(), a.end());
    sort(b.begin(), b.end());
    // max-heap of (sum, i, j); i indexes a (sorted asc), j indexes b (sorted asc)
    priority_queue<tuple<long long,int,int>> pq;
    set<pair<int,int>> visited;
    pq.push({(long long)a[n-1] + b[n-1], n-1, n-1});
    visited.insert({n-1, n-1});
    vector<int> result;
    while ((int)result.size() < k && !pq.empty()) {
      auto [sum, i, j] = pq.top();
      pq.pop();
      result.push_back((int)sum);
      if (i - 1 >= 0 && !visited.count({i-1, j})) {
        visited.insert({i-1, j});
        pq.push({(long long)a[i-1] + b[j], i-1, j});
      }
      if (j - 1 >= 0 && !visited.count({i, j-1})) {
        visited.insert({i, j-1});
        pq.push({(long long)a[i] + b[j-1], i, j-1});
      }
    }
    return result;
  }
};

class Solution{
public:
    int stockBuySell(vector<int> arr, int n){
        if (n == 0) return 0;
        // State-machine DP for at most two transactions.
        // buy1: best running value after first buy (we hold, having paid)
        // sell1: best profit after first sell
        // buy2: best running value after second buy
        // sell2: best profit after second sell
        long long buy1 = LLONG_MIN, sell1 = 0, buy2 = LLONG_MIN, sell2 = 0;
        for (int i = 0; i < n; i++) {
            long long p = arr[i];
            buy1 = max(buy1, -p);
            sell1 = max(sell1, buy1 + p);
            buy2 = max(buy2, sell1 - p);
            sell2 = max(sell2, buy2 + p);
        }
        return (int)sell2;
    }
};

class Solution{
    public:
    void solve(int i, int j, vector<vector<int>> &grid, int n, string move, vector<string> &ans, vector<vector<int>> &vis) {
        if (i == n - 1 && j == n - 1) {
            ans.push_back(move);
            return;
        }
        // Down
        if (i + 1 < n && !vis[i + 1][j] && grid[i + 1][j] == 1) {
            vis[i][j] = 1;
            solve(i + 1, j, grid, n, move + 'D', ans, vis);
            vis[i][j] = 0;
        }
        // Left
        if (j - 1 >= 0 && !vis[i][j - 1] && grid[i][j - 1] == 1) {
            vis[i][j] = 1;
            solve(i, j - 1, grid, n, move + 'L', ans, vis);
            vis[i][j] = 0;
        }
        // Right
        if (j + 1 < n && !vis[i][j + 1] && grid[i][j + 1] == 1) {
            vis[i][j] = 1;
            solve(i, j + 1, grid, n, move + 'R', ans, vis);
            vis[i][j] = 0;
        }
        // Up
        if (i - 1 >= 0 && !vis[i - 1][j] && grid[i - 1][j] == 1) {
            vis[i][j] = 1;
            solve(i - 1, j, grid, n, move + 'U', ans, vis);
            vis[i][j] = 0;
        }
    }

    vector<string> findPath(vector<vector<int> > &grid) {
        int n = grid.size();
        vector<string> ans;
        if (n == 0) return ans;
        vector<vector<int>> vis(n, vector<int>(n, 0));
        if (grid[0][0] == 1) {
            solve(0, 0, grid, n, "", ans, vis);
        }
        return ans;
    }
};

class Solution {
public:
    int timer = 1;
    void dfs(int node, int parent, vector<int> adj[], vector<int>& vis,
             vector<int>& tin, vector<int>& low, vector<int>& mark) {
        vis[node] = 1;
        tin[node] = low[node] = timer;
        timer++;
        int child = 0;
        for (auto it : adj[node]) {
            if (it == parent) continue;
            if (!vis[it]) {
                dfs(it, node, adj, vis, tin, low, mark);
                low[node] = min(low[node], low[it]);
                if (low[it] >= tin[node] && parent != -1) {
                    mark[node] = 1;
                }
                child++;
            } else {
                low[node] = min(low[node], tin[it]);
            }
        }
        if (child > 1 && parent == -1) {
            mark[node] = 1;
        }
    }

    vector<int> articulationPoints(int n, vector<int> adj[]) {
        vector<int> vis(n, 0);
        vector<int> tin(n, 0), low(n, 0), mark(n, 0);
        timer = 1;
        for (int i = 0; i < n; i++) {
            if (!vis[i]) {
                dfs(i, -1, adj, vis, tin, low, mark);
            }
        }
        vector<int> ans;
        for (int i = 0; i < n; i++) {
            if (mark[i] == 1) ans.push_back(i);
        }
        if (ans.size() == 0) return {-1};
        return ans;
    }
};

class Solution {
  public:
    int LongestBitonicSequence(vector<int> arr) {
        int n = arr.size();
        vector<int> left(n, 1), right(n, 1);
        // left[i] = length of longest strictly increasing subsequence ending at i
        for (int i = 0; i < n; i++)
            for (int prev = 0; prev < i; prev++)
                if (arr[prev] < arr[i])
                    left[i] = max(left[i], left[prev] + 1);
        // right[i] = length of longest strictly decreasing subsequence starting at i
        for (int i = n - 1; i >= 0; i--)
            for (int nxt = i + 1; nxt < n; nxt++)
                if (arr[nxt] < arr[i])
                    right[i] = max(right[i], right[nxt] + 1);
        int ans = 0;
        for (int i = 0; i < n; i++)
            ans = max(ans, left[i] + right[i] - 1);
        return ans;
    }
};

class Solution{
    public:
    vector<vector<int>> floodFill(vector<vector<int>> &image,
                                  int sr, int sc, int newColor) {
        int n = image.size();
        if (n == 0) return image;
        int m = image[0].size();
        int oldColor = image[sr][sc];
        if (oldColor == newColor) return image;
        queue<pair<int,int>> q;
        q.push({sr, sc});
        image[sr][sc] = newColor;
        int dr[] = {-1, 1, 0, 0};
        int dc[] = {0, 0, -1, 1};
        while (!q.empty()) {
            auto [r, c] = q.front(); q.pop();
            for (int k = 0; k < 4; k++) {
                int nr = r + dr[k];
                int nc = c + dc[k];
                if (nr >= 0 && nr < n && nc >= 0 && nc < m
                    && image[nr][nc] == oldColor) {
                    image[nr][nc] = newColor;
                    q.push({nr, nc});
                }
            }
        }
        return image;
    }
};

class Solution {
public:
    string longestPalindrome(string s) {
        int n = s.size();
        if (n == 0) return "";
        int start = 0, maxLen = 1;
        auto expand = [&](int l, int r) {
            while (l >= 0 && r < n && s[l] == s[r]) {
                if (r - l + 1 > maxLen) {
                    maxLen = r - l + 1;
                    start = l;
                }
                l--; r++;
            }
        };
        for (int i = 0; i < n; i++) {
            expand(i, i);     // odd length center
            expand(i, i + 1); // even length center
        }
        return s.substr(start, maxLen);
    }
};

class Solution {
    public:
    int whileLoop(int d) {
        int count = 0;
        long long sum = 0;
        int num = 1;
        while (count < 50) {
            if (num % 10 == d) {
                sum += num;
                count++;
            }
            num++;
        }
        return (int)sum;
    }
};
